// In the Worker:
class UploadWorker(...) : CoroutineWorker(...) {
    override suspend fun doWork(): Result {
        for (i in 0..100 step 10) {
            setProgress(workDataOf("progress" to i))
            delay(500) // actual upload work
        }
        return Result.success()
    }
}

// In the ViewModel:
class UploadViewModel(private val workManager: WorkManager) : ViewModel() {
    fun observeUpload(workId: UUID): StateFlow<Int> {
        return workManager.getWorkInfoByIdFlow(workId)
            .map { it?.progress?.getInt("progress", 0) ?: 0 }
            .stateIn(viewModelScope, SharingStarted.Lazily, 0)
    }
}
